def prime_num(n: int) -> bool:
    """Return True if n is a prime number, else False."""
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:          # Only check up to sqrt(n)
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6                 # Check numbers of the form 6k ± 1
    return True

