{"code":"def get_median(a, b, n):
    """Return median of two sorted arrays a, b of same size n.
       Uses O(log n) recursive divide-and-conquer.
    """
    # Helper to get median of single array slice a[l:r] (inclusive indices via length m)
    def median(arr, start, end):
        m_len = end - start + 1
        mid = start + m_len // 2
        if m_len % 2 == 0:
            return (arr[mid-1] + arr[mid]) / 2.0
        else:
            return float(arr[mid])

    def _get_median(a, b, start_a, end_a, start_b, end_b):
        m_len = end_a - start_a + 1
        # base cases
        if m_len == 1:
            return (a[start_a] + b[start_b]) / 2.0
        if m_len == 2:
            return (max(a[start_a], b[start_b]) + min(a[end_a], b[end_b])) / 2.0

        m1 = median(a, start_a, end_a)
        m2 = median(b, start_b, end_b)

        if m1 == m2:
            return m1

        # if m1 < m2, then median must be in a.right + b.left
        if m1 < m2:
            if m_len % 2 == 0:
                return _get_median(a, b, start_a + m_len//2 - 1, end_a, start_b, start_b + m_len//2)
            else:
                return _get_median(a, b, start_a + m_len//2, end_a, start_b, start_b + m_len//2)
        else:
            # m1 > m2: median in a.left + b.right
            if m_len % 2 == 0:
                return _get_median(a, b, start_a, start_a + m_len//2, start_b + m_len//2 - 1, end_b)
            else:
                return _get_median(a, b, start_a, start_a + m_len//2, start_b + m_len//2, end_b)

    if n <= 0:
        raise ValueError("Arrays must be non-empty")
    if len(a) != n or len(b) != n:
        raise ValueError("Array lengths must match n")

    return _get_median(a, b, 0, n-1, 0, n-1)

# given test
assert get_median([1, 12, 15, 26, 38], [2, 13, 17, 30, 45], 5) == 16.0

# some extra tests
assert get_median([1], [2], 1) == 1.5
assert get_median([1, 2], [3, 4], 2) == 2.5
assert get_median([1, 3, 5], [2, 4, 6], 3) == 3.5
print('All tests passed')"}

