def remove_parenthesis(strings):
    """Remove the first parenthesized area (and adjacent extra spaces)
    from the first string in the list, and return that cleaned string.
    """
    if not strings:
        return ""

    def process(s: str) -> str:
        start = s.find('(')
        if start == -1:
            return s.strip()
        end = s.find(')', start)
        if end == -1:
            # No closing parenthesis; just return text before '('
            return s[:start].strip()

        # Text before and after the parentheses
        before = s[:start].rstrip()
        after = s[end+1:].lstrip()

        # Join with a single space if both parts exist
        if before and after:
            return (before + " " + after).strip()
        return (before or after).strip()

    return process(strings[0])


# Given test
assert remove_parenthesis(["python (chrome)"]) == "python"
```

