```python
def are_Equal(arr1, arr2, n, m):
    # Check if given sizes match actual lengths
    if n != len(arr1) or m != len(arr2):
        return False

    # If sizes differ, arrays can't be equal
    if n != m:
        return False

    # Count elements in first array
    counts = {}
    for x in arr1:
        counts[x] = counts.get(x, 0) + 1

    # Subtract counts using second array
    for x in arr2:
        if x not in counts:
            return False
        counts[x] -= 1
        if counts[x] < 0:
            return False

    # All counts must be zero
    return all(v == 0 for v in counts.values())


# Example test
assert are_Equal([1,2,3], [3,2,1], 3, 3) == True
```

