{"code": "def lcs_of_three(a, b, c, n1, n2, n3):
    # 3D DP: dp[i][j][k] = LCS length of a[:i], b[:j], c[:k]
    # Dimensions (n1+1) x (n2+1) x (n3+1)
    dp = [[[0]*(n3+1) for _ in range(n2+1)] for __ in range(n1+1)]

    for i in range(1, n1+1):
        for j in range(1, n2+1):
            for k in range(1, n3+1):
                if a[i-1] == b[j-1] == c[k-1]:
                    dp[i][j][k] = dp[i-1][j-1][k-1] + 1
                else:
                    dp[i][j][k] = max(
                        dp[i-1][j][k],
                        dp[i][j-1][k],
                        dp[i][j][k-1]
                    )
    return dp[n1][n2][n3]


