{"code":"from collections import Counter

def n_common_words(text, n):
    # Normalize to lowercase and split on whitespace
    words = text.lower().split()
    if n <= 0:
        return []
    # Count frequencies
    counts = Counter(words)
    # To respect first occurrence order when counts tie, we can sort by (-count, first_index)
    first_index = {}
    for i, w in enumerate(words):
        if w not in first_index:
            first_index[w] = i
    # Sort words by count desc, then by first occurrence asc
    sorted_words = sorted(counts.items(), key=lambda kv: (-kv[1], first_index[kv[0]]))
    # Take top n
    return sorted_words[:n]

