def to_immutable(x):
    """Recursively convert lists inside x to tuples so the structure becomes hashable."""
    if isinstance(x, list):
        return tuple(to_immutable(e) for e in x)
    return x

def check_subset(lst, sub):
    """
    Return True if every element of `sub` (possibly nested lists)
    appears in `lst`. Comparison is structural: nesting and order must match.
    """
    set_lst = {to_immutable(inner) for inner in lst}
    return all(to_immutable(inner) in set_lst for inner in sub)


# Given example
assert check_subset([[1, 3], [5, 7], [9, 11], [13, 15, 17]] ,[[1, 3],[13,15,17]]) == True
```

This converts each nested structure into tuples recursively so they can be compared and used in a set, then checks that every element from `sub` is present in `lst`.

