```python
import math

def lobb_num(n: int, m: int) -> int:
    """
    Compute the Lobb number L(n, m).

    Uses the identity:
        L(n, m) = C(2n, n - m) - C(2n, n - m - 1)
    valid for 0 <= m <= n, otherwise 0.
    """
    if m < 0 or m > n:
        return 0

    def comb(a, b):
        if b < 0 or b > a:
            return 0
        return math.comb(a, b)

    return comb(2 * n, n - m) - comb(2 * n, n - m - 1)


# given test
assert int(lobb_num(5, 3)) == 35
```

