```python
def is_Two_Alter(s: str) -> bool:
    # Strings of length < 2 cannot be alternating with two characters
    if len(s) < 2:
        return False

    # Collect distinct characters in order of appearance
    chars = []
    for ch in s:
        if ch not in chars:
            chars.append(ch)
            # More than 2 distinct characters is invalid
            if len(chars) > 2:
                return False

    # Must be exactly 2 distinct characters
    if len(chars) != 2:
        return False

    c1, c2 = chars

    # Check if the string matches a strict alternating pattern
    def matches_pattern(first, second):
        for i, ch in enumerate(s):
            expected = first if i % 2 == 0 else second
            if ch != expected:
                return False
        return True

    # Pattern can start with either of the two characters
    return matches_pattern(c1, c2) or matches_pattern(c2, c1)


# given test
assert is_Two_Alter("abab") == True
```

