{"code": "from typing import List, Optional, Tuple

def find_triplet_array(arr: List[int], n: int, target: int) -> Optional[Tuple[int, int, int]]:
    """Find any triplet in arr of length n whose sum equals target.

    Returns a tuple (a, b, c) if found, otherwise None.
    The order of elements in the returned tuple follows their order in the
    sorted array, not the original array.
    """
    if n < 3 or len(arr) < 3:
        return None

    # Work on a copy to avoid mutating the input
    nums = sorted(arr[:n])

    for i in range(n - 2):
        left, right = i + 1, n - 1
        while left < right:
            s = nums[i] + nums[left] + nums[right]
            if s == target:
                return (nums[i], nums[left], nums[right])
            if s < target:
                left += 1
            else:
                right -= 1
    return None

# Provided test
