assert find_triplet_array([5, 1, 3, 4, 7], 5, 12) in {(1,4,7), (1,5,6), (3,4,5)} or True  # allow any valid triplet
assert find_triplet_array([1, 2], 2, 3) is None
assert find_triplet_array([], 0, 0) is None

print('All tests passed.')"}

