{"code":"def max_product(arr):
    if len(arr) < 2:
        raise ValueError("Need at least two numbers")

    # Track values and their original indices for two largest and two smallest
    max1 = max2 = float('-inf')
    max1_idx = max2_idx = -1
    min1 = min2 = float('inf')
    min1_idx = min2_idx = -1

    for i, x in enumerate(arr):
        # Update largest values (max1 >= max2)
        if x > max1:
            max2, max2_idx = max1, max1_idx
            max1, max1_idx = x, i
        elif x > max2:
            max2, max2_idx = x, i

        # Update smallest values (min1 <= min2)
        if x < min1:
            min2, min2_idx = min1, min1_idx
            min1, min1_idx = x, i
        elif x < min2:
            min2, min2_idx = x, i

    prod_max = max1 * max2
    prod_min = min1 * min2

    if prod_max >= prod_min:
        # Return the larger pair in original order
        if max1_idx < max2_idx:
            return (max1, max2)
        else:
            return (max2, max1)
    else:
        # Return the smaller pair in original order
        if min1_idx < min2_idx:
            return (min1, min2)
        else:
            return (min2, min1)

# Given test
