{"code":"from functools import lru_cache


def dealnnoy_num(m: int, n: int) -> int:
    """Return the Delannoy number D(m, n).

    D(m,n) counts paths from (0,0) to (m,n) with steps (1,0), (0,1), (1,1).
    Recurrence: D(0,0)=1; D(m,0)=1; D(0,n)=1; otherwise
    D(m,n) = D(m-1,n) + D(m-1,n-1) + D(m,n-1).
    """

    @lru_cache(maxsize=None)
    def D(i: int, j: int) -> int:
        if i == 0 and j == 0:
            return 1
        if i == 0 or j == 0:
            return 1
        return D(i - 1, j) + D(i - 1, j - 1) + D(i, j - 1)

    if m < 0 or n < 0:
        raise ValueError("m and n must be non-negative")
    return D(m, n)


# provided test
assert dealnnoy_num(3, 4) == 129

print("All tests passed.")
"}

